/* adm-master-customer-sql-oracle.xml  selectCustomerCountInfo */
SELECT COUNT(1)
FROM TADMIN_MST_CUSTOMER A


		#{SEARCH_CONDITION}

/* adm-master-customer-sql-oracle.xml selectCustomerInfo */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT A.OWKEY , C.OWNM , A.ACKEY , A.ACNM , A.ACSUMMARYNM , A.CGRP , A.ACTYPE2 , A.ACTYPEDT , A.ZIPCD , A.ADDR1 , A.ADDR2 , A.CEO , A.TEL1 , A.SALESPERSONKEY , UR.URNM AS SALESPERSONNAME , A.REPACKEY , B.ACNM AS REP_ACNM , A.BIZTYPE , A.BIZCTG , A.REGNO , A.ACGRADE , A.POINT , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TADMIN_MST_CUSTOMER A LEFT OUTER JOIN TADMIN_MST_CUSTOMER B ON A.OWKEY = B.OWKEY AND A.REPACKEY = B.ACKEY LEFT OUTER JOIN TADMIN_MST_UR UR ON A.SALESPERSONKEY = UR.URKEY LEFT OUTER JOIN TADMIN_MST_OW C ON A.OWKEY = C.OWKEY
#{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY A.UPDATEDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* adm-master-customer-sql-oracle.xml  selectAccountGroupByUsrList */
SELECT OD.OWCDDTKEY AS ACCOUNTGROUP
  FROM TADMIN_MST_OWCD_DT OD
 WHERE OD.OWKEY = #{owkey}		     
   AND OD.OWCDHDKEY = #{accountgroupcode}
   AND OD.DELYN = 'N'
   AND OD.OWCDDTVALUE IN
                    (

                        SELECT #{item} AS OWCD_DTVALUE 

                    )

/* adm-master-customer-sql-oracle.xml  selectTAdminMstCt */
SELECT '0' AS CHK
	 ,CTKEY
	 ,CTNM
	 ,(
	SELECT OWKEY FROM TADMIN_MST_OW WHERE OWKEY = #{owkey}
) AS OWKEY
FROM TADMIN_MST_CT
WHERE DELYN = 'N'
ORDER BY CTKEY

mapper.update:
/* adm-master-customer-sql-oracle.xml  updateTmsShpgLocT */
UPDATE TT_SHPG_LOC_T TMS
   SET ( TMS.SHPGLOCNM
	   , TMS.SHPGLOCTYPCD
	   , TMS.ADDRID
	   , TMS.TELNO1
	   , TMS.STTCD
       , TMS.UPDATEDATE
       , TMS.UPDATEURKEY ) = ( SELECT A.ACNAME
									, '1'
									, M.ADDRID
									, A.TEL1
									, 'Y'
									,#{interfaceDate}
									,#{interfaceUrkey}
								FROM TADMIN_INTF_CUSTOMERS A
									 JOIN TADMIN_MST_CUSTOMER M
									   ON A.ACKEY = M.ACKEY
									  AND M.OWKEY = #{owkey}
							   WHERE TMS.SHPGLOCCD = A.ACKEY
								 AND A.INTERFACE_ID = #{interfaceId}
								 AND A.REQUESTDT = #{requestDt}
								 AND A.EMPSAVEYN = 'N' /*직원저장대상여부*/
								 )
WHERE EXISTS(
	SELECT 1
	  FROM TADMIN_INTF_CUSTOMERS C
	 WHERE TMS.SHPGLOCCD = C.ACKEY
	   AND C.INTERFACE_ID = #{interfaceId}
	   AND C.REQUESTDT = #{requestDt}
	   AND C.EMPSAVEYN = 'N' /*직원저장대상여부*/
		 )

/* adm-master-customer-sql-oracle.xml  updateUsrInfo */
UPDATE TADMIN_MST_UR
   SET URNM = #{urname}
     , URTYP = #{urtyp}
     , CP = #{cp}
     , DEPTCD = #{point}
     , UPDATEURKEY = #{interfaceUrkey}
     , UPDATEDATE = #{interfaceDate}
 WHERE URKEY = #{urkey}

mapper.insert:
		/* adm-master-customer-sql-oracle.xml  insertUsrInfo */
		INSERT INTO TADMIN_MST_UR
		(
		       URKEY
		     , URNM
		     , URPW
		     , EXP
		     , LAKEY
		     , TZKEY
		     , URTYP
		     , CP
		     , DEPTCD
			 , CLOSDATE
		     , INSERTDATE
			 , INSERTURKEY
   		  	 , UPDATEDATE
			 , UPDATEURKEY
		) VALUES (
			   #{urkey}
		     , #{urname}
		     , #{urpw}
		     , SUBSTR(#{closdate}, 1, 12)
		     , 'KOR'
		     , 'UTC+0900'		    
		     , #{urtyp}
		     , #{cp}
		     , #{point}
		     , #{closdate}
		     , #{interfaceDate}	     
		     , #{interfaceUrkey}
		     , #{interfaceDate}	     
		     , #{interfaceUrkey}
		)
